//PROCEDIMENTO PARA CLONAR A OPERAÇÃO DE TRANSPORTE\\
For Each Order EmpCod, FilCod, OpeCod //BUSCA A OPERAÇÃO PASSADA POR PARÂMETRO Where EmpCod = &parmEmpCod //EMPRESA Where FilCod = &parmFilCod //FILIAL Where OpeCod = &parmOpeCod //OPERAÇÃO
&AuxOpeTipVia = OpeTipVia //DEFINE O TIPO DA VIAGEM (PADRÃO, OU TAC_AGRAGADO) &NewOpeCod = UltimoCodigoEmpresa.Udp(domParCod.OPERACAOTRANSPORTE, &parmEmpCod, &parmFilCod) //RETORNA O ÚLTIMO CÓDIGO REGISTRADO DE OPERAÇÃO
//ATRIBUI OS VALORES DA OPERAÇÃO PASSADA POR PARÂMETRO À NOVA OPERAÇÃO\\
//CAPA DA OPERAÇÃO New EmpCod = &parmEmpCod //EMPRESA FilCod = &parmFilCod //FILIAL OpeCod = &NewOpeCod //CÓDIGO OPERAÇÃO OpeMdfeFilCod = 0 //CÓDIGO DA FILIAL DA MDFE OpeMdfeCod = 0 //MDFE OpeDta = &Today //DATA DE EMISSÃO OpeTipVia = OpeTipVia //TIPO DA VIAGEM OpeEmiGra = OpeEmiGra //MODALIDADE DA OPERAÇÃO (TRUE = TRANSFERENCIABANCARIA; FALSE = eFRETE) OpeMatCnpj = OpeMatCnpj //MATRIZ CNPJ EMITENTE OpeNro = '' //VAZIO PORQUE O NÚMERO SERÁ ATRIBUIDO AO ADICIONAR UM PAGAMENTO
//SE A VIAGEM FOR DO TIPO PADRÃO\\ If &AuxOpeTipVia = PefServiceTipoViagem.Padrao OpeDtaIni = &Today //DATA DE INICIO DA VIAGEM OpeNcm = OpeNcm //NCM DE NATUREZA (4 DÍGITOS NO MÁXIMO) OpePso = OpePso //PESO TOTAL DA MERCADORIA OpeTipEmb = OpeTipEmb //TIPO DA EMBALAGEM OpeDesCod = OpeDesCod //CÓDIGO DO DESTINATÁRIO OpeEntDoc = OpeEntDoc //ENTREGA DA DOCUMENTAÇÃO (REDE CREDENCIADA, OU CLIENTE) OpeQtdSaq = OpeQtdSaq //QUANTIDADE DO SAQUE OpeQtdTra = OpeQtdTra //QUANTIDADE DE TRANSFERÊNCIAS OpeTipCar = OpeTipCar //TIPO DA CARGA (LIMITADO A 2 DIGITOS E VAI DE 01 A 99) OpeAltDes = OpeAltDes //SE É CARGA DE ALTO DESEMPENHO OpeDesCom = OpeDesCom //SE É DESTINAÇÃO COMERCIAL OpeFrtRet = OpeFrtRet //SE TEM FRETE DE RETORNO OpeCepRet = OpeCepRet //O CEP DO FRETE DE RETORNO OpeDisRet = OpeDisRet //A DISTÂNCIA DO RETORNO EndIf //##############################\\
OpeDtaFim = &Today.AddDays(1) //DATA FINAL DA VIAGEM (GENÉRICA POR AGORA)
//CONTRATADO OpeConCod = OpeConCod //CÓDIGO DO CONTRATADO (TRANSPORTADORA) OpeConCnpj = OpeConCnpj //CNPJ DO CONTRATADO (TRANSPORTADORA) OpeConRntrc = OpeConRntrc //RNTRC DO CONTRATADO (TRANSPORTADORA)
//MOTORISTA OpeMotCod = OpeMotCod //CÓDIGO DO MOTORISTA OpeMotCnpj = OpeMotCnpj //CPF DO MOTORISTA OpeMotCnh = OpeMotCnh //CNH DO MOTORISTA OpeMotTelDdd = OpeMotTelDdd //DDD DO TELEFONE DO MOTORISTA OpeMotTelNro = OpeMotTelNro //TELEFONE DO MOTORISTA
//CONTRATANTE OpeAntCod = OpeAntCod //CÓDIGO DO CONTRATANTE (SERÁ O CÓDIGO DA FILIAL EMITENTE)
//SUB-CONTRATANTE OpeSubCon = OpeSubCon //CÓDIGO DO SUB-CONTRATANTE OpeSubConCiot = OpeSubConCiot //CIOT DE ORIGEM REFERENTE A OPERAÇÃO DO SUB-CONTRATANTE
//CONSIGNATÁRIO OpeSigCod = OpeSigCod //CÓDIGO DO CONSIGNATÁRIO
//TOMADOR OpeTomCod = OpeTomCod //CÓDIGO DO TOMADOR
OpeResPgtFrt = OpeResPgtFrt //RESPONSÁVEL PELO PAGAMENTO DO FRETE OpeNroCiot = '' //NÚMERO DO CIOT (VAZIO PORQUE SERÁ EMITIDO AINDA OpeSts = Status_Ciot.Digitando //STATUS DO CIOT (DIGITANDO PORQUE NÃO FOI EMITIDO UM CIOT AINDA OpeNfeVlrFrtUnd = OpeNfeVlrFrtUnd //VALOR DA NFE POR UNIDADE EndNew
//VEICULOS &NewOpeVeiCod = 0 For Each Order EmpCod, FilCod, OpeCod, OpeVeiCod
&NewOpeVeiCod += 1 New EmpCod = EmpCod //EMPRESA FilCod = FilCod //FILIAL OpeCod = &NewOpeCod //CÓDIGO DA OPERAÇÃO OpeVeiCod = &NewOpeVeiCod //CÓDIGO DO VEÍCULO OpeVeiPla = OpeVeiPla //PLACA DO VEÍCULO OpeVeiObs = OpeVeiObs //SE HOUVE ALGUMA OBSERVAÇÃO OpeVeiUF = OpeVeiUF //UF DO VEÍCULO OpeVeiTipCar = OpeVeiTipCar //TIPO DE CARROCERIA (SÓ ACEITA VEÍCULOS DE TRAÇÃO) EndNew
EndFor
//IMPOSTOS &NewOpeImpCod = 0 For Each Order EmpCod, FilCod, OpeCod, OpeImpCod
&NewOpeImpCod += 1 New EmpCod = EmpCod //EMPRESA FilCod = FilCod //FILIAL OpeCod = &NewOpeCod //CÓDIGO DA OPERAÇÃO OpeImpCod = &NewOpeImpCod //CÓDIGO DO IMPOSTO (HAVERÁ APENAS UM) OpeImpIRRF = OpeImpIRRF //VALOR DESTINADO AO IRRF OpeImpSest = OpeImpSest //VALOR DESTINADO AO SEST / SENAT OpeImpInss = OpeImpInss //VALOR DESTINADO AO INSS OpeImpIssqn = OpeImpIssqn //VALOR DESTINADO AO ISSQN OpeImpOut = OpeImpOut //VALOR DESTINADO A OUTROS IMPOSTOS NÃO PREVISTOS EndNew
EndFor
//SE A VIAGEM FOR DO TIPO PADRÃO, VAI ADICIONAR UMA VIAGEM E OS SEUS VALORES, ADICIONAR OS PAGAMENTOS E ADICIONAR AS NFE If &AuxOpeTipVia = PefServiceTipoViagem.Padrao
&NewOpePgtCod = 0 &TotAdiantamento = 0 &TotQuitacao = 0
//PAGAMENTOS For Each Order EmpCod, FilCod, OpeCod, OpePgtCod
&NewOpePgtCod += 1 &OpePgtNro = Padl(Str(EmpCod),6,'0') + Padl(Str(FilCod),6,'0')+ Padl(Str(&NewOpePgtCod),6,'0')
New EmpCod = EmpCod //EMPRESA FilCod = FilCod //FILIAL OpeCod = &NewOpeCod //CÓDIGO DA OPERAÇÃO OpePgtCod = &NewOpePgtCod //CÓDIGO DO PAGAMENTO OpePgtNro = &OpePgtNro //NÚMERO DO PAGAMENTO OpeDtaLib = &Today //DATA EM QUE O PAGAMENTO SERÁ LIBERADO PARA SAQUE OpePgtVal = OpePgtVal //VALOR DO PAGAMENTO OpePgtTip = OpePgtTip //MODALIDADE DO PAGAMENTO (SERÁ IGUAL AO DA CAPA) OpePgtCat = OpePgtCat //CATEGORIA DO PAGAMENTO (ADIANTAMENTO, ESTADIA, QUITACAO, SEMCATEGORIA) OpePgtDoc = OpePgtDoc //DOCUMENTO RELACIONADO A VIAGEM OpePgtBan = OpePgtBan //CÓDIGO DA INSTITUIÇÃO BANCÁRIA OpePgtAge = OpePgtAge //AGÊNCIA DA CONTA OpePgtCon = OpePgtCon //NÚMERO DA CONTA DO CONTRATADO (COM DÍGITO SE HOUVER) OpePgtConTip = OpePgtConTip //TIPO DA CONTA DO CONTRATADO OpePgtInfAdd = OpePgtInfAdd //INFORMAÇÕES ADICIONAIS OpePgtSts = Status_AtivoInativo.ATIVO //STATUS DO PAGAMENTO OpePgtSit = Status_AbertoFechado.Aberto //SITUAÇÃO DO PAGAMENTO EndNew
Do Case Case OpePgtCat = PefServiceCategoriaPagamento.Adiantamento //SE ADIANTAMENTO, ACRESCENTA O VALOR AO TOTAL DE ADIANTAMENTOS &TotAdiantamento += OpePgtVal
Case OpePgtCat = PefServiceCategoriaPagamento.Quitacao //SE QUITAÇÃO, ACRESCENTA O VALOR AO TOTAL DE QUITAÇÃO &TotQuitacao += OpePgtVal EndCase
EndFor
//VIAGENS &NewOpeViaCod = 0 For Each Order EmpCod, FilCod, OpeCod, OpeViaCod Where OpeViaSts = Status_Autorizado.AUTORIZADO //TODAS AS VIAGENS COM O STATUS AUTORIZADO
&AuxOpeViaCod = OpeViaCod &NewOpeViaCod += 1 New EmpCod = EmpCod //EMPRESA FilCod = FilCod //FILIAL OpeCod = &NewOpeCod //CÓDIGO DA OPERAÇÃO OpeViaCod = &NewOpeViaCod //CÓDIGO DA VIAGEM OpeTipPgt = OpeTipPgt //MODALIDADE DA VIAGEM (SERÁ IGUAL AO DA CAPA) OpeDstCidCod = OpeDstCidCod //CÓDIGO IBGE DA CIDADE DE DESTINO OpeDstCidCep = OpeDstCidCep //CEP DA CIDADE DE DESTINO OpeDstCidUfe = OpeDstCidUfe //UF DA CIDADE DE DESTINO OpeOriCidCod = OpeOriCidCod //CÓDICO IBGE DA CIDADE DE ORIGEM OpeOricidCep = OpeOricidCep //CEP DA CIDADE DE ORIGEM OpeOriCidUfe = OpeOriCidUfe //UF DA CIDADE DE ORIGEM OpeNroDoc = OpeNroDoc //DOCUMENTO RELACIONADO A VIAGEM (DEVERÁ SER MAIOR QUE 10 CARACTERES) OpeViaDstPer = OpeViaDstPer //DISTÂNCIA TOTAL PERCORRIDA OpeViaSts = Status_Autorizado.AUTORIZADO //STATUS DA VIAGEM EndNew
//VALORES DA VIAGEM &NewOpeValCod = 0 For Each Order EmpCod, FilCod, OpeCod, OpeViaCod, OpeValCod
&NewOpeValCod += 1 New EmpCod = EmpCod //EMPRESA FilCod = FilCod //FILIAL OpeCod = &NewOpeCod //CÓDIGO DA OPERAÇÃO OpeViaCod = &NewOpeViaCod //CÓDIGO DA VIAGEM OpeValCod = &NewOpeValCod //CÓDIGO DO VALOR DA VIAGEM OpeTotAdi = &TotAdiantamento //TOTAL DE ADIANTAMENTO OpeTotQui = &TotQuitacao //TOTAL DE QUITAÇÃO OpeTotCom = OpeTotCom //TOTAL DESTINADO AO COMBUSTÍVEL OpeTotPed = OpeTotPed //TOTAL DESTINADO AO PEDÁGIO OpeTotSeg = OpeTotSeg //TOTAL DESTINADO AO SEGURO OpeTotOutDeb = OpeTotOutDeb //TOTAL PARA OUTROS DÉBITOS OpeTotOutDebJus = OpeTotOutDebJus //JUSTIFICATIVA DOS OUTROS DÉBITOS OpeTotOutCre = OpeTotOutCre //TOTAL PARA OUTROS CRÉDITOS OpeTotOutCreJus = OpeTotOutCreJus //JUSTIFICATIVA DOS OUTROS CRÉDITOS EndNew Exit EndFor
Exit EndFor
//DOCUMENTOS FISCAIS &NewOpeNfeCod = 0 For Each Order EmpCod, FilCod, OpeCod, OpeNfeCod
&NewOpeNfeCod += 1 New EmpCod = EmpCod //EMPRESA FilCod = FilCod //FILIAL OpeCod = &NewOpeCod //CÓDIGO DA OPERAÇÃO OpeNfeCod = &NewOpeNfeCod //CÓDIGO DO DOCUMENTO FISCAL OpeNfeNro = OpeNfeNro //NÚMERO DO DOCUMENTO FISCAL OpeNfeSer = OpeNfeSer //NÚMERO DA SERIE DO DOCUMENTO FISCAL OpeNfeVlrTot = OpeNfeVlrTot //VALOR TOTAL DO DOCUMENTO FISCAL OpeNfeVlrUni = OpeNfeVlrUni //VALOR POR UNIDADE OpeNfeNcm = OpeNfeNcm //NCM PRINCIPAL DO DOCUMENTO FISCAL OpeNfeUndMed = OpeNfeUndMed //UNIDADE DE MEDIDA DA MERCADORIA (SEMPRE KG) OpeNfeTipCal = OpeNfeTipCal //TIPO DE CALCULO OpeNfeQtdMerEmb = OpeNfeQtdMerEmb //QUANTIDADE TE MERCADORIA EMBARCADA (A SOMA DE TODAS AS MERCADORIAS DARÁ O VALOR DE OpePso) OpeNfeTolPerVlr = OpeNfeTolPerVlr //VALOR DE PERDA OpeNfeDifFrtTip = OpeNfeDifFrtTip //TIPO DA DIFERENÇA OpeNfeDifFrtBas = OpeNfeDifFrtBas //TIPO DA BASE DE CALCULO OpeNfeTolTip = OpeNfeTolTip //TIPO DE TOLERANCIA OpeNfeMarGanTip = OpeNfeMarGanTip //TIPO DE MARGEM DE GANHO OpeNfeMarGanVlr = OpeNfeMarGanVlr //VALOR DA MARGEM DE GANHO OpeNfeMarPerTip = OpeNfeMarPerTip //TIPO DE MARGEM DE PERDA OpeNfeMarPerVlr = OpeNfeMarPerVlr //VALOR DA MARGEM DE PERDA OpeNfeChv = OpeNfeChv //CHAVE DO DOCUMENTO FISCAL EndNew
EndFor
EndIf
Exit EndFor Commit
